import anthropic

client = anthropic.Anthropic()


def stream_response(prompt: str, system: str = "") -> str:
    """Stream tokens as they arrive; collect and return the full text."""
    kwargs = {
        "model":      "claude-opus-4-8",
        "max_tokens": 1024,
        "messages":   [{"role": "user", "content": prompt}],
    }
    if system:
        kwargs["system"] = system

    full_text = []
    with client.messages.stream(**kwargs) as stream:
        for text_chunk in stream.text_stream:
            print(text_chunk, end="", flush=True)   # display as it arrives
            full_text.append(text_chunk)
    print()  # newline after stream
    return "".join(full_text)


result = stream_response("Walk me through gradient descent step by step.")

import time
import anthropic
from anthropic import RateLimitError, APIStatusError, APIConnectionError

client = anthropic.Anthropic()


def call_with_retry(
    prompt: str,
    max_retries: int = 4,
    base_delay: float = 1.0,
) -> str:
    """
    Retry on transient failures with exponential backoff.
    Raises immediately on non-retryable errors (4xx except 429).
    """
    for attempt in range(max_retries + 1):
        try:
            response = client.messages.create(
                model="claude-opus-4-8",
                max_tokens=512,
                messages=[{"role": "user", "content": prompt}],
            )
            return response.content[0].text

        except RateLimitError:
            if attempt == max_retries:
                raise
            delay = base_delay * (2 ** attempt)
            print(f"Rate limited. Retrying in {delay:.1f}s…")
            time.sleep(delay)

        except APIConnectionError:
            if attempt == max_retries:
                raise
            time.sleep(base_delay * (2 ** attempt))

        except APIStatusError as e:
            if e.status_code >= 500:
                if attempt == max_retries:
                    raise
                time.sleep(base_delay * (2 ** attempt))
            else:
                raise   # 4xx (bad request, auth) — don't retry
    raise RuntimeError("Unreachable")
